SELECT B.ID, B.BOOK_NAME, B.PUBLISHER_HOUSE, B.PRICE, B.ENTERED_AT, B.BOOK_OWNER_ID, U.NAME AS BOOK_OWNER_NAME, BOP.NICKNAME AS BOOK_OWNER_NICKNAME, B.COMMON_CODE_ID AS GENRE_CODE, CC_GENRE.CODE_NAME AS GENRE_NAME, BC.COMMON_CODE_ID AS LOCATION_CODE, CC_LOC.CODE_NAME AS LOCATION_NAME, BC.ID AS BOOK_CASE_ID, BCT.CODE AS BOOK_CASE_TYPE_CODE, B.ISBN, B.AUTHOR, B.THUMBNAIL_URL FROM BOOK B JOIN USERS U ON B.BOOK_OWNER_ID = U.ID JOIN BOOK_CASE BC ON B.BOOK_CASE_ID = BC.ID JOIN BOOK_CASE_TYPE BCT ON BC.BOOK_CASE_TYPE_ID = BCT.ID LEFT JOIN BOOK_OWNER_PROFILE BOP ON B.BOOK_OWNER_ID = BOP.BOOK_OWNER_ID LEFT JOIN COMMON_CODE CC_GENRE ON CC_GENRE.GROUP_CODE = 'BOOK_TYPE' AND CC_GENRE.CODE = B.COMMON_CODE_ID LEFT JOIN COMMON_CODE CC_LOC ON CC_LOC.GROUP_CODE = 'LOCATION' AND CC_LOC.CODE = BC.COMMON_CODE_ID WHERE B.STATE = 'NORMAL' AND B.DELETED_AT IS NULL AND U.DELETED_AT IS NULL
AND B.BOOK_OWNER_ID = #{bookOwnerId}
AND (UPPER(B.BOOK_NAME) LIKE '%' || UPPER(#{search}) || '%' OR UPPER(B.PUBLISHER_HOUSE) LIKE '%' || UPPER(#{search}) || '%')
AND B.COMMON_CODE_ID = #{genreCode}
AND BC.COMMON_CODE_ID = #{locationCode}
ORDER BY B.ENTERED_AT DESC
